onClick:
{{
qryValidarClaveAnulacion.run()
.then(() => {

  if (
    Number(qryValidarClaveAnulacion.data?.[0]?.clave_valida) !== 1
  ) {

    showAlert(
      "Clave de anulación incorrecta",
      "error"
    );

    return;

  }

  return qrySPAnular.run();

})
.then(() => {

  if (!qrySPAnular.data?.[0]) {
    return;
  }

  closeModal("mdlAnularSP");

  resetWidget("inpClaveAnularSP");

  showAlert(
    "Solicitud anulada: " +
    qrySPAnular.data[0].numero_solicitud_pago,
    "success"
  );

  qrySPConsultar.run();

})
.catch((err) => {

  showAlert(
    err.message,
    "error"
  );

});
}}
